content:
nextflow.enable.dsl=2

include { step_2AS_mapping__bowtie } from '../steps/step_2AS_mapping__bowtie'
include { step_2AS_mapping__ivar } from '../steps/step_2AS_mapping__ivar'
include { step_4AN_genes__prokka } from '../steps/step_4AN_genes__prokka'
include { step_4TY_lineage__pangolin } from '../steps/step_4TY_lineage__pangolin'
include { extractKey; getEmpty } from '../functions/common.nf'
include { getSingleInput;getReferenceOptional;getReference } from '../functions/parameters.nf'

def PROKKA_KINGDOM = 'Viruses'

workflow module_draft_genome {
    take: 
        reads
        reference 
        referenceGB
    main:
        reads.cross(reference) { extractKey(it) }.multiMap { 
            reads: it[0] // riscd, reads
            refs:  it[1][1..3] // riscd, code, path
        }.set { readsAndReferences }

        step_2AS_mapping__bowtie(readsAndReferences.reads, readsAndReferences.refs)

        consensus = step_2AS_mapping__ivar(readsAndReferences.reads, readsAndReferences.refs).consensus

        consensus.cross(referenceGB) { extractKey(it) }.map { 
            [ it[0][0], it[0][1], PROKKA_KINGDOM, it[1][1], it[1][2], it[1][3] ] // riscd assembly kingdom riscd_ref refid refpath]

        }.set { consensusKingdomReference }

        step_4AN_genes__prokka(consensusKingdomReference)
}

workflow  {
    module_draft_genome(getSingleInput(), getReference('fa'), getReferenceOptional('gb'))
}

nextflow.enable.dsl=2

include { step_2AS_filtering__seqio } from '../steps/step_2AS_filtering__seqio'
include { step_3TX_species__vdabricate } from '../steps/step_3TX_species__vdabricate'
include { extractKey } from '../functions/common.nf'
include { getInput;getReference;getDS } from '../functions/parameters.nf'

workflow module_scaffolds_filtering {    
    take: 
        assembled
        reference 
        abricatedatabase 
    main:
        assembled.cross(abricatedatabase) { extractKey(it) }
            .map { 
                [ it[0][0], it[0][1], it[1][1] ] 
            }
            .set { ch_scaffolds_db }

        ch_calls = step_3TX_species__vdabricate(ch_scaffolds_db)

        ch_calls.cross(assembled) { extractKey(it) }
            .cross(reference) { extractKey(it) }
            .multiMap { 
                calls: it[0][0]
                assembly: it[0][1]
                reference: it[1][1..3]
            }
            .set { ch_filt }

        step_2AS_filtering__seqio(ch_filt.calls, ch_filt.assembly, ch_filt.reference)
}

workflow {
    ch_input = getInput()
    ch_ref = getReference('fa')
    ch_db = Channel.of([ getDS(), 'viruses_TREF' ])
    module_scaffolds_filtering(ch_input, ch_ref, ch_db)
}

nextflow.enable.dsl=2

include { step_4TY_lineage__westnile; getReferenceForLineage } from '../steps/step_4TY_lineage__westnile'
include { step_2AS_mapping__ivar } from '../steps/step_2AS_mapping__ivar'
include { extractKey } from '../functions/common.nf'
include { getSingleInput } from '../functions/parameters.nf'

workflow module_westnile {
    take: 
        reads        
    main:
        ch_lineage = step_4TY_lineage__westnile(reads)

        reads.cross(ch_lineage) { extractKey(it) }
            .multiMap { 
                reads: it[0]
                reference: getReferenceForLineage(it[1][1])
            }
            .set { ch_ready }

        ivar_out = step_2AS_mapping__ivar(ch_ready.reads, ch_ready.reference)

    emit:
        consensus = ivar_out.consensus
}

workflow {
    ch_input = getSingleInput()
    module_westnile(ch_input)
}

nextflow.enable.dsl=2

include { module_denovo } from '../modules/module_denovo'
include { module_scaffolds_filtering } from '../modules/module_scaffolds_filtering'
include { module_draft_genome } from '../modules/module_draft_genome'
include { extractKey } from '../functions/common.nf'
include { getSingleInput;getHost;getReference;getReferenceOptional;getDS } from '../functions/parameters.nf'

workflow module_vdraft {
    take: 
        reads
        host
        reference
        referenceGB
        abricateDatabase
    main:
        denovo_out = module_denovo(reads, host)

        denovo_out.assembled
            .cross(reference) { extractKey(it) }
            .cross(abricateDatabase) { extractKey(it) }
            .multiMap { 
                assembly: it[0][0][0..1]
                reference: it[0][1]
                abricateDatabase: it[1]
            }
            .set { ch_scaff_filt }

        module_scaffolds_filtering(ch_scaff_filt.assembly, ch_scaff_filt.reference, ch_scaff_filt.abricateDatabase)

        denovo_out.depleted
            .cross(reference) { extractKey(it) }
            .cross(referenceGB) { extractKey(it) }
            .multiMap {
                depleted: it[0][0][0..1]
                reference: it[0][1]
                referenceGB: it[1]
            }
            .set { ch_draft }

        module_draft_genome(ch_draft.depleted, ch_draft.reference, ch_draft.referenceGB)
}

workflow {
    ch_in = getSingleInput()
    ch_host = getHost()
    ch_ref_fa = getReference('fa')
    ch_ref_gb = getReferenceOptional('gb')
    ch_db = Channel.of([ getDS(), 'viruses_TREF' ])

    module_vdraft(ch_in, ch_host, ch_ref_fa, ch_ref_gb, ch_db)
}

nextflow.enable.dsl=2

include { step_2AS_mapping__bowtie } from '../steps/step_2AS_mapping__bowtie'
include { step_3TX_species__kmerfinder; getBacterialReferencePath } from '../steps/step_3TX_species__kmerfinder'
include { step_4AN_genes__prokka } from '../steps/step_4AN_genes__prokka'
include { step_4AN_AMR__abricate } from '../steps/step_4AN_AMR__abricate'
include { step_4AN_AMR__staramr } from '../steps/step_4AN_AMR__staramr'
include { step_4TY_cgMLST__chewbbaca } from '../steps/step_4TY_cgMLST__chewbbaca'
include { step_4TY_MLST__mlst } from '../steps/step_4TY_MLST__mlst'
include { step_4TY_flaA__flaA } from '../steps/step_4TY_flaA__flaA'
include { csv2map; extractKey; getEmpty } from '../functions/common.nf'
include { getTrimmedReads; getAssembly } from '../functions/parameters.nf'

workflow module_typing_bacteria {
    take: 
        trimmed
        assembly
    main:
        kmer_results = step_3TX_species__kmerfinder(assembly)
        ch_assigned = kmer_results.assigned_species

        if (!params.skip_bestref_mapping) {
            trimmed.cross(ch_assigned) { extractKey(it) }
                .multiMap { 
                    trimmed: it[0]
                    species: it[1][1]
                    referencePath: it[1][2]
                }
                .set { ch_mapping }

            step_2AS_mapping__bowtie(ch_mapping.trimmed, ch_mapping.referencePath)
        } 

        step_4AN_AMR__abricate(assembly)

        ch_prokka_in = assembly.map { [ it[0], it[1], 'Bacteria', '-', '-', getEmpty() ] }
        step_4AN_genes__prokka(ch_prokka_in)

        assembly.cross(ch_assigned) { extractKey(it) }
            .multiMap { 
                assembly: it[0]
                species: it[1][1]
            }
            .set { ch_typing }

        step_4AN_AMR__staramr(ch_typing.assembly, ch_typing.species)
        step_4TY_MLST__mlst(ch_typing.assembly)
        step_4TY_flaA__flaA(ch_typing.assembly, ch_typing.species)
        step_4TY_cgMLST__chewbbaca(ch_typing.assembly, ch_typing.species, '')

    emit:
        genus_species = ch_assigned
}

workflow {
    ch_trimmed = getTrimmedReads(true)
    ch_assembly = getAssembly()
    module_typing_bacteria(ch_trimmed, ch_assembly)
}

nextflow.enable.dsl=2

include { step_1PP_filtering__bowtie } from '../steps/step_1PP_filtering__bowtie'
include { step_2AS_denovo__spades } from '../steps/step_2AS_denovo__spades'
include { extractKey } from '../functions/common.nf'
include { getSingleInput;getReference } from '../functions/parameters.nf'

workflow module_filtered_denovo {
    take: 
        reads
        reference 
    main:
        reads.cross(reference) { extractKey(it) }.multiMap { 
            reads: it[0] // riscd, reads
            refs:  it[1][1..3] // riscd, code, path
        }.set { readsAndReferences }

        filtered = step_1PP_filtering__bowtie(readsAndReferences.reads, readsAndReferences.refs)       
        assembled = step_2AS_denovo__spades(filtered)
    emit:
        assembled = assembled
        filtered = filtered
}

workflow {
    module_filtered_denovo(getSingleInput(), getReference('fa'))
}

nextflow.enable.dsl=2

include { step_0SQ_rawreads__fastq } from '../steps/step_0SQ_rawreads__fastq'
include { step_1PP_trimming__trimmomatic } from '../steps/step_1PP_trimming__trimmomatic'
include { step_1PP_trimming__fastp } from '../steps/step_1PP_trimming__fastp'
include { step_3TX_class__kraken } from '../steps/step_3TX_class__kraken'
include { getInput;hasFastqData;hasEnoughFastqData;isIlluminaPaired;isIonTorrent;isNanopore } from '../functions/parameters.nf'
include { isBacterium } from '../functions/sampletypes.nf'

workflow module_reads_processing {
    take: 
        rawReads
    main:
        rawReads.branch {
            with_data: hasFastqData(it[1])
            no_reads: true
        }.set { ch_raw }

        step_0SQ_rawreads__fastq(ch_raw.with_data)        

        ch_raw.with_data.branch {
            illumina: isIlluminaPaired(it[1])
            ion: isIonTorrent(it[1])
            nanopore: isNanopore(it[1])
            other: true 
        }.set { ch_tech }

        ch_tech.illumina.branch {
            bacteria: isBacterium(it)
            other: true 
        }.set { ch_illumina }

        proc_trimmomatic = step_1PP_trimming__trimmomatic(ch_illumina.other)

        ch_fastp_in = ch_tech.ion.mix(ch_illumina.bacteria)
        proc_fastp = step_1PP_trimming__fastp(ch_fastp_in)

        ch_trimmed = proc_trimmomatic.trimmed.mix(proc_fastp.trimmed)

        ch_trimmed.branch {
            with_data: hasEnoughFastqData(it[1])
            insufficient: true
        }.set { ch_final }

        step_3TX_class__kraken(ch_final.with_data)

    emit:
        no_reads = ch_raw.no_reads
        trimmed_with_data = ch_final.with_data
        insufficient_number_of_reads = ch_final.insufficient
}

workflow {
    module_reads_processing(getInput())
}

nextflow.enable.dsl=2

include { step_2AS_mapping__ivar } from '../steps/step_2AS_mapping__ivar'
include { step_4TY_lineage__pangolin } from '../steps/step_4TY_lineage__pangolin'
include { extractKey } from '../functions/common.nf'
include { getSingleInput } from '../functions/parameters.nf'

def referenceCode = 'NC_045512.2'
def referencePath = "${params.assets_dir}/module_covid_emergency/NC_045512.fasta"
def referenceRiscd = '220308-020220308005121273-2AS_import-external'

workflow module_covid_emergency {
    take: 
        trimmed
    main:
        trimmed.multiMap {
            trimmed: it
            reference: [ referenceRiscd, referenceCode, file(referencePath) ]
        }.set { trAndRef }

        ivar_out = step_2AS_mapping__ivar(trAndRef.trimmed, trAndRef.reference)
        step_4TY_lineage__pangolin(ivar_out.consensus)
}

workflow {
    module_covid_emergency(getSingleInput())
}

nextflow.enable.dsl=2

include { step_1PP_hostdepl__bowtie } from '../steps/step_1PP_hostdepl__bowtie'
include { step_2AS_mapping__bowtie } from '../steps/step_2AS_mapping__bowtie'
include { extractKey } from '../functions/common.nf'
include { getSingleInput;getHostOptional;getReference } from '../functions/parameters.nf'

workflow module_vdraft_light {
    take: 
        trimmedReads
        host
        reference
    main:
        trimmedReads.cross(host) { extractKey(it) }
            .map { [ it[0][0], it[0][1], it[1][1] ] }
            .branch {
                with_host: it[1][1]
                without_host: true
            }
            .set { ch_branched }

        ch_depleted = step_1PP_hostdepl__bowtie(ch_branched.with_host)

        ch_branched.without_host
            .mix(ch_depleted)
            .map { it[0,1] }
            .set { ch_ready }

        ch_ready.cross(reference) { extractKey(it) }
            .multiMap { 
                reads: it[0]
                refs:  it[1][1..3]
            }
            .set { ch_final }

        step_2AS_mapping__bowtie(ch_final.reads, ch_final.refs)
}

workflow {
    ch_in = getSingleInput()
    ch_host = getHostOptional()
    ch_ref = getReference('fa')
    module_vdraft_light(ch_in, ch_host, ch_ref)
}

nextflow.enable.dsl=2

include { step_2AS_denovo__unicycler } from '../steps/step_2AS_denovo__unicycler'
include { step_4AN_AMR__blast } from '../steps/step_4AN_AMR__blast'
include { getSingleInput;getGenusSpeciesOptional } from '../functions/parameters.nf'
include { extractKey } from '../functions/common.nf'

workflow module_enterotoxin_saureus_finder {
    take: 
        trimmed
        genus_species
    main:
        assembly = step_2AS_denovo__unicycler(trimmed)

        assembly.cross(genus_species) { extractKey(it) }
            .multiMap { 
                assembly: it[0]
                species: it[1]
            }.set { assemblyAndSpecies }
        step_4AN_AMR__blast(assemblyAndSpecies.assembly, assemblyAndSpecies.species)
}

workflow {
    module_enterotoxin_saureus_finder(getSingleInput(), getGenusSpeciesOptional())
}

nextflow.enable.dsl=2

include { taskMemory } from '../functions/common.nf'
include { getInput;getReferenceUnkeyed;param;optional } from '../functions/parameters.nf'

def SUMMARY_DATE_ALIASES = param('multi_clustering__reportree__summary_date_aliases')  
def SAMPLE_COLUMN = param('multi_clustering__reportree__summary_sample_column')  
def GEO_RESOLUTION_COLUMNS = param('multi_clustering__reportree__summary_geo_column')  
def TRAITS_COLUMNS = param('multi_clustering__augur__traits_columns') 

workflow multi_clustering__augur {
    take: 
      reference
      raw_metadata
      geodata
      ref2
    main:  
      metadata = prepare_metadata(raw_metadata).metadata
      fastas = getInput().flatMap { it[1] }.collect()
      alignment = align(fastas, reference).alignment
      tree_raw = tree(alignment).tree_raw
      tree = refine(tree_raw, alignment, metadata).tree
      nt_muts = ancestral(tree, alignment, reference).nt_muts
      aa_muts = translate(tree, nt_muts, reference).aa_muts
      traits = traits(tree, metadata).traits
      export(tree, metadata, refine.out.branch_lengths, traits, nt_muts, aa_muts, geodata)
  }

workflow {
    reference = getReferenceUnkeyed('gb')      
    multi_clustering__augur(reference, param('metadata'), param('geodata'), reference)
}

nextflow.enable.dsl=2

include { taskMemory;flattenPath } from '../functions/common.nf'
include { getReferenceUnkeyed;getResult;getInput;param } from '../functions/parameters.nf'

def GEO_RESOLUTION_COLUMNS = param('multi_clustering__reportree__summary_geo_column')
def SUMMARY_DATE_ALIASES = param('multi_clustering__reportree__summary_date_aliases')
def SAMPLE_COLUMN = param('multi_clustering__reportree__summary_sample_column')

IMAGES = [
  '2.2.1': 'staphb/cfsan-snp-pipeline:2.2.1',
  '2.0.2': 'cfsanbiostatistics/snp-pipeline@sha256:448787923371ade95217982814db25efb1e01287a8180b523d76a9f093f97d01'
]

def DOCKER_IMAGE = IMAGES[param('multi_clustering__cfsan__version')] ?: (exit 2, "params (multi_clustering__cfsan__version) not valid");

workflow multi_clustering__cfsan {
    take: 
        input
        reference
        metadata
        geodata
    main:
        snpma = cfsan_snp_pipeline(input, reference).snpma
        nwk = iqtree(snpma).nwk
        augur(nwk, metadata, geodata)
}

workflow {
    reads = getInput()
        .map { it[1] }
        .toSortedList( { a, b -> a[0] <=> b[0] } )
        .flatten()     
        .collect()  
    multi_clustering__cfsan(reads, getReferenceUnkeyed('fa'), param('metadata'), param('geodata'));
}

nextflow.enable.dsl=2

include { parseRISCD;taskMemory } from '../functions/common.nf'
include { _getAlleles;param } from '../functions/parameters.nf'

def GEO_RESOLUTION_COLUMNS = param('multi_clustering__reportree__summary_geo_column')
def SUMMARY_DATE_ALIASES = param('multi_clustering__reportree__summary_date_aliases')
def SAMPLE_COLUMN = param('multi_clustering__reportree__summary_sample_column')

workflow multi_clustering__grapetree {
    take: 
        input
        metadata
        geodata
    main:
        cgMLST = extract_cgMLST(input.collect()).cgMLST
        dists(cgMLST)
        nwk_nj = grapetree(cgMLST).nwk_nj
        augur(nwk_nj, metadata, geodata)
}

workflow {
    multi_clustering__grapetree(getInput(), param('metadata'), param('geodata'));
}

def getInput() {
    if (!params.containsKey('input')) {
      exit 2, "missing required param: input";
    }
    def schema = params.containsKey('schema') ? params.schema : null
    assert params.input instanceof ArrayList
    params.input.inject(Channel.empty()) {
        res, val -> res.mix(_getAlleles(val.cmp, val.riscd, schema))
    }        
}

nextflow.enable.dsl=2

include { getInput;param } from '../functions/parameters.nf'
include { taskMemory;flattenPath } from '../functions/common.nf'

def GEO_RESOLUTION_COLUMNS = param('multi_clustering__reportree__summary_geo_column')
def SUMMARY_DATE_ALIASES = param('multi_clustering__reportree__summary_date_aliases')
def SAMPLE_COLUMN = param('multi_clustering__reportree__summary_sample_column')

workflow multi_clustering__ksnp3 {
    take: 
        input
        kmers_size
        analysis_type
        metadata
        geodata
    main:
        input
          .map { it[1] }
          .collect()
          .set { inputSet }
        matrix = ksnp3(inputSet, kmers_size, analysis_type).fasta
        iqtree(matrix)
        grapetree(matrix)
        augur(iqtree.out.nwk, metadata, geodata)
}

workflow {
    multi_clustering__ksnp3(getInput(), param('kmers_size'), param('analysis_type'), param('metadata'), param('geodata'));
}

nextflow.enable.dsl=2

include { module_reads_processing } from '../modules/module_reads_processing'
include { module_wgs_bacteria } from '../modules/module_wgs_bacteria'
include { module_typing_bacteria } from '../modules/module_typing_bacteria'
include { module_covid_emergency } from '../modules/module_covid_emergency'
include { module_vdraft } from '../modules/module_vdraft'
include { module_westnile } from '../modules/module_westnile'
include { module_qc_quast } from '../modules/module_qc_quast'
include { step_4TY_lineage__pangolin } from '../steps/step_4TY_lineage__pangolin'


include { getSingleInput;param } from '../functions/parameters.nf'
include { getEmpty;extractKey;isFastqRiscd;isFastaRiscd } from '../functions/common.nf'
include { isNegativeControl;isNegativeControlSarsCov2;isPositiveControlSarsCov2;isVirus;isWNV;isBacterium;isSarsCov2;isAmpliseq } from '../functions/sampletypes.nf'

workflow ngsmanager_fastq {
    take: 
      rawReads  
    main:
      try {       
        trimmed = module_reads_processing(rawReads).trimmed_with_data

        trimmed.branch {
            bacteria: isBacterium(it)
            sarscov2: isSarsCov2(it) || isNegativeControlSarsCov2(it) || isPositiveControlSarsCov2(it)
            negative_control: isNegativeControl(it)
            viruses: isVirus(it)
            wnv: isWNV(it)
            ampliseq: isAmpliseq(it)
            other: true
        }
        .set { branched }

        /* bacteria stuff here */
        assemblyBacteria = module_wgs_bacteria(branched.bacteria)
        crossedBacteriaData = branched.bacteria.cross(assemblyBacteria) { extractKey(it) }.multiMap { 
          trimmed: it[0]
          assembly: it[1]
        }
        module_typing_bacteria(crossedBacteriaData.trimmed, crossedBacteriaData.assembly)

        /* sarscov2 stuff here */
        module_covid_emergency(branched.sarscov2)

        /* viruses stuff here */
        // no extra modules executed

        /* wnv stuff here */
        module_westnile(branched.wnv)
      } catch (t) {
          exit 1, "unexpected exception: ${t.asString()}"
      }

}

workflow ngsmanager_fasta {
    take: 
      fasta
    main:
      try {      
        module_qc_quast(fasta)

        fasta.branch {
            bacteria: isBacterium(it)
            sarscov2: isSarsCov2(it) || isNegativeControlSarsCov2(it) || isPositiveControlSarsCov2(it)
            negative_control: isNegativeControl(it)
            viruses: isVirus(it)
            wnv: isWNV(it)
            ampliseq: isAmpliseq(it)
            other: true
        }
        .set { branched }

        /* bacteria stuff here */
        module_typing_bacteria(Channel.empty(), branched.bacteria)

        /* sarscov2 stuff here */
        step_4TY_lineage__pangolin(branched.sarscov2)       

        /* wnv stuff here */
        module_westnile(branched.wnv)        
      } catch (t) {
          exit 1, "unexpected exception: ${t.asString()}"
      }     
}

workflow pipeline_ngsmanager {
  if (isFastqRiscd(param('riscd'))){
    ngsmanager_fastq(getSingleInput())
  } else if (isFastaRiscd(param('riscd'))){
    ngsmanager_fasta(getSingleInput())
  } else {
    exit 2, "unexpected riscd provided: ${param('riscd')}"
  }
}

workflow {
  pipeline_ngsmanager()
}

nextflow.enable.dsl=2

include { getInput;param;optional } from '../functions/parameters.nf'
include { flattenPath } from '../functions/common.nf'

workflow multi_pangenome__panaroo {
    take: 
        input
    main:      
        input
            .map { it[1] }
            .collect()
            .set { gffs }   
        panaroo(gffs)
}

workflow {
    multi_pangenome__panaroo(getInput())
}

nextflow.enable.dsl=2

include { step_4TY_plasmid__mobsuite } from '../steps/step_4TY_plasmid__mobsuite'
include { isSpeciesSupported;taskMemory;flattenPath;parseMetadataFromFileName;executionMetadata } from '../functions/common.nf'
include { getSingleInput;isIlluminaPaired;isCompatibleWithSeqType;isIonTorrent;param } from '../functions/parameters.nf'

POINFINDER_GENUS_ALLOWED = [
  'campylobacter',
  'enterococcus_faecalis',
  'enterococcus_faecium',
  'escherichia_coli',
  'helicobacter_pylori',
  'klebsiella',
  'mycobacterium_tuberculosis',
  'neisseria_gonorrhoeae',
  'plasmodium_falciparum',
  'salmonella',
  'staphylococcus_aureus'
]

def ex = executionMetadata()

def getPointfinderParam(gsp) {
 try {  
    def genus_species = gsp ? gsp.toLowerCase() : ''
    def (genus, species) = genus_species.contains("_") ? genus_species.split('_') : [ genus_species, null ]
    if (POINFINDER_GENUS_ALLOWED.contains(genus_species)) {
        return genus_species;
    }       
    if (POINFINDER_GENUS_ALLOWED.contains(genus)) {
        return genus
    }
    return ''
  } catch(Throwable t) {
      exit 1, "unexpected exception: ${t.asString()}"
  } 
}

workflow module_plasmids {
    take: 
        assembly
        genus_species
    main:
        plasmids = step_4TY_plasmid__mobsuite(assembly).plasmids

        plasmids.multiMap { it ->
            riscd: it[0]
            plasmids: it[1]
        }.set { branched }

        input = branched.riscd.combine(branched.plasmids.flatten())
        staramr(input, genus_species)
}

workflow {
    module_plasmids(getSingleInput(), param('genus_species'))
