    }.set { coverageRefAndConsensus }

    check_out = coverage_check(coverageRefAndConsensus, METHOD)
    coverageBasic = check_out.coverage_basic
    ch_extra_keyed = minmax_out.coverage_extra.map { [it[0] + "-" + it[1], it] }
